import java.io.IOException;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode the user input to prevent XSS attacks
        String safeUserInput = encodeForHTML(userInput);

        String output = "Hello, " + safeUserInput + "!";

        response.getWriter().write("<h1>" + output + "</h1>");
    }

    // Encode user input for HTML content
    private String encodeForHTML(String input) {
        if (input == null) {
            return "";
        }

        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
